  ('diplomatic-0248a032-moex-00556', 'diplomatic-0248a032', 'diplomatic-0248a032-moex-110-cf527099', 'sub-diplomatic-0248a032-06', NULL, 'single_choice', '參考瑞士中立化之實踐，下列敘述何者正確？', '["一國得單方面宣告中立化而成為中立化國家", "有關大國訂定條約對一國中立化地位給予集體保證", "須經由聯合國大會通過，一國才能取得中立化地位", "一個中立國有不參加任何國際組織的義務"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:58+00:00", "source_pdf_sha1": "705e62bb3941", "answer_pdf_sha1": "4633c06a9e7e", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "101", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際法(含國際公法與國際私法)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-國際法組"}'::jsonb, NULL),
  ('diplomatic-0248a032-moex-00557', 'diplomatic-0248a032', 'diplomatic-0248a032-moex-110-cf527099', 'sub-diplomatic-0248a032-06', NULL, 'single_choice', '國際法中的「先占」概念已成為領土取得的重要要件。下列敘述何者錯誤？', '["國際法中之「先占」概念來自國內私法之「時效取得」概念", "國家發現無主地後，仍需有效控制始能取得領土主權", "實際上持續並和平展現國家功能係先占的重要要件之一", "「發現」給予國家期待權可以在合理期間內完成先占"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:58+00:00", "source_pdf_sha1": "705e62bb3941", "answer_pdf_sha1": "4633c06a9e7e", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "101", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際法(含國際公法與國際私法)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-國際法組"}'::jsonb, NULL),
  ('diplomatic-0248a032-moex-00558', 'diplomatic-0248a032', 'diplomatic-0248a032-moex-110-cf527099', 'sub-diplomatic-0248a032-06', NULL, 'single_choice', '1951年「難民地位公約」所列符合難民資格的畏懼受迫害之因素，不包括下列何者？', '["國籍", "戰爭", "屬於某一社會團體", "具有某種政治見解"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:58+00:00", "source_pdf_sha1": "705e62bb3941", "answer_pdf_sha1": "4633c06a9e7e", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "101", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際法(含國際公法與國際私法)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-國際法組"}'::jsonb, NULL),
  ('diplomatic-0248a032-moex-00559', 'diplomatic-0248a032', 'diplomatic-0248a032-moex-110-cf527099', 'sub-diplomatic-0248a032-06', NULL, 'single_choice', '依據聯合國海洋法公約，下列敘述何者正確？', '["島嶼是四面環水並在高潮時高於水平面的自然形成的陸地區域，故人造島無法擁有領海", "若低潮高地全部與大陸或島嶼的距離超過領海的寬度，則該高地可以有其自己的領海", "所有國家的船舶均享有無害通過他國領海的權利，沿海國不得制定關於無害通過的法律或規章", "沿海國應在通過領海的外國船舶上行使刑事管轄權，以逮捕與在該船舶通過期間船上所犯任何 罪行有關的任何人，或進行與該罪行有關的任何調查"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:58+00:00", "source_pdf_sha1": "705e62bb3941", "answer_pdf_sha1": "4633c06a9e7e", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "101", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際法(含國際公法與國際私法)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-國際法組"}'::jsonb, NULL),
  ('diplomatic-0248a032-moex-00560', 'diplomatic-0248a032', 'diplomatic-0248a032-moex-110-cf527099', 'sub-diplomatic-0248a032-06', NULL, 'single_choice', '關於「國籍」，下列敘述何者錯誤？', '["一國得對具有該國國籍之人民行使屬人管轄權", "各國國內法關於取得國籍之方式有相同之規定", "國民得請求其國家保護，並得依國際法規範享有與國籍相關的利益", "一國原則上得依其國內法規定決定何人為其國民"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:58+00:00", "source_pdf_sha1": "705e62bb3941", "answer_pdf_sha1": "4633c06a9e7e", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "101", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際法(含國際公法與國際私法)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-國際法組"}'::jsonb, NULL),
  ('diplomatic-0248a032-moex-00561', 'diplomatic-0248a032', 'diplomatic-0248a032-moex-110-cf527099', 'sub-diplomatic-0248a032-06', NULL, 'single_choice', '依國家對國際不法行為的責任條款草案規定，一個國家犯了國際不法行為而需負國際責任時，下 列何者通常不被視為國家解除責任的方式？', '["恢復原狀", "補償", "抵償", "反措施"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:58+00:00", "source_pdf_sha1": "705e62bb3941", "answer_pdf_sha1": "4633c06a9e7e", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "101", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際法(含國際公法與國際私法)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-國際法組"}'::jsonb, NULL),
  ('diplomatic-0248a032-moex-00562', 'diplomatic-0248a032', 'diplomatic-0248a032-moex-110-cf527099', 'sub-diplomatic-0248a032-06', NULL, 'single_choice', '有關《聯合國憲章》第51條自衛權之規定，下列敘述何者錯誤？', '["第51條肯認一國有個別或集體自衛之固有權利", "行使自衛權之前提係一國受到「武力攻擊」", "自衛權之習慣法地位起源於1986年國際法院尼加拉瓜案判決", "「武力攻擊」之認定條件包含攻擊之「規模和效果」"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:58+00:00", "source_pdf_sha1": "705e62bb3941", "answer_pdf_sha1": "4633c06a9e7e", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "101", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際法(含國際公法與國際私法)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-國際法組"}'::jsonb, NULL),
  ('diplomatic-0248a032-moex-00563', 'diplomatic-0248a032', 'diplomatic-0248a032-moex-110-cf527099', 'sub-diplomatic-0248a032-06', NULL, 'single_choice', '依維也納外交關係公約第19條，如使館館長缺位或不能執行職務時，應由下列何者暫代使館館長？', '["臨時代辦", "外交團團長", "代辦", "無任所大使"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:58+00:00", "source_pdf_sha1": "705e62bb3941", "answer_pdf_sha1": "4633c06a9e7e", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "101", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際法(含國際公法與國際私法)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-國際法組"}'::jsonb, NULL),
  ('diplomatic-0248a032-moex-00564', 'diplomatic-0248a032', 'diplomatic-0248a032-moex-110-cf527099', 'sub-diplomatic-0248a032-06', NULL, 'single_choice', '依馬爾喀什設立世界貿易組織協定（Marrakesh Agreement Establishing the World Trade Organization）規定，世界貿易組織（WorldTradeOrganization）原則上優先採取何種方式做決策？', '["二分之一多數決", "共識決", "三分之二多數決", "四分之三多數決"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:58+00:00", "source_pdf_sha1": "705e62bb3941", "answer_pdf_sha1": "4633c06a9e7e", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "101", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際法(含國際公法與國際私法)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-國際法組"}'::jsonb, NULL),
  ('diplomatic-0248a032-moex-00565', 'diplomatic-0248a032', 'diplomatic-0248a032-moex-110-cf527099', 'sub-diplomatic-0248a032-06', NULL, 'single_choice', '關於國際法院，下列敘述何者錯誤？', '["國際法院的法官共15名，其中不得有2人為同一國家之國民", "除了第一次選出的法官中之10人外，國際法院的法官任期9年，並得連選連任", "在法院得為訴訟當事國者，限於國家", "非聯合國會員國無法成為國際法院規約的當事國"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:58+00:00", "source_pdf_sha1": "705e62bb3941", "answer_pdf_sha1": "4633c06a9e7e", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "101", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際法(含國際公法與國際私法)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-國際法組"}'::jsonb, NULL)
